fil["958"]= "GUID-CF5B00A7-AE42-4189-85E9-4BF759498BB8.html@@@I/O Settings@@@The alarm input and alarm output of hybrid DVR, NVR, or CVR are allocated by device automatically after allocating the video and audio digital channel. You can configure the alarm input and output parameters, such as alarm input name, alarm output name, arming time, alarm device type, linkage actions, and so on...";
